"use client";

import { useEffect, useMemo, useState } from "react";
import { useAccount, useBalance, useSendTransaction } from "wagmi";
import { parseEther } from "viem";
import { io } from "socket.io-client";

import { TOKENS } from "@/lib/tokens";

import BalanceCard from "./components/BalanceCard";
import TokenSelector from "./components/TokenSelector";
import SendForm from "./components/SendForm";
import ReceiveModal from "./components/ReceiveModal";
import VirtualCard from "./components/VirtualCard";
import TransactionHistory from "./components/TransactionHistory";
import BottomNav from "./components/BottomNav";

/* ================= SOCKET ================= */
const socket = io("https://iopndex.onrender.com", {
  transports: ["websocket"],
  });

  /* ================= FORMAT ================= */
  function formatBalance(value: any) {
    if (!value) return "0.00";
      return Number(value.formatted || 0).toFixed(2);
      }

      /* ================= PAGE ================= */
      export default function PayPage() {
        const { address, isConnected } = useAccount();

          const [recipient, setRecipient] = useState("");
            const [amount, setAmount] = useState("");
              const [tokenSymbol, setTokenSymbol] = useState("OPN");

                const [txHash, setTxHash] = useState<string | null>(null);

                  const [liveTxs, setLiveTxs] = useState<any[]>([]);

                    /* MODALS */
                      const [showReceive, setShowReceive] = useState(false);
                        const [showCard, setShowCard] = useState(false);

                          const token = useMemo(
                              () => TOKENS.find((t) => t.symbol === tokenSymbol),
                                  [tokenSymbol]
                                    );

                                      const { data: balance } = useBalance({ address });

                                        const { sendTransactionAsync } = useSendTransaction();

                                          /* ================= SEND TX ================= */
                                            async function sendTx() {
                                                if (!isConnected || !address) {
                                                      alert("Connect wallet first");
                                                            return;
                                                                }

                                                                    if (!recipient || !amount) {
                                                                          alert("Missing fields");
                                                                                return;
                                                                                    }

                                                                                        try {
                                                                                              /* 1. WALLET TX */
                                                                                                    const tx = await sendTransactionAsync({
                                                                                                            to: recipient as `0x${string}`,
                                                                                                                    value: parseEther(amount),
                                                                                                                          });

                                                                                                                                setTxHash(tx);

                                                                                                                                      /* 2. BACKEND RECORD */
                                                                                                                                            await fetch("https://iopndex.onrender.com/api/send", {
                                                                                                                                                    method: "POST",
                                                                                                                                                            headers: { "Content-Type": "application/json" },
                                                                                                                                                                    body: JSON.stringify({
                                                                                                                                                                              from: address,
                                                                                                                                                                                        to: recipient,
                                                                                                                                                                                                  amount,
                                                                                                                                                                                                            token: tokenSymbol,
                                                                                                                                                                                                                      hash: tx,
                                                                                                                                                                                                                                chainId: 984,
                                                                                                                                                                                                                                        }),
                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                    setRecipient("");
                                                                                                                                                                                                                                                          setAmount("");

                                                                                                                                                                                                                                                                alert("Transaction sent 🚀");
                                                                                                                                                                                                                                                                    } catch (err) {
                                                                                                                                                                                                                                                                          console.error(err);
                                                                                                                                                                                                                                                                                alert("Transaction failed ❌");
                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                                        /* ================= SOCKET ================= */
                                                                                                                                                                                                                                                                                          useEffect(() => {
                                                                                                                                                                                                                                                                                              socket.on("connect", () => {
                                                                                                                                                                                                                                                                                                    console.log("Socket connected:", socket.id);
                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                            socket.on("newTx", (tx) => {
                                                                                                                                                                                                                                                                                                                  setLiveTxs((prev) => [tx, ...prev]);
                                                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                                                          socket.on("txConfirmed", (data) => {
                                                                                                                                                                                                                                                                                                                                setLiveTxs((prev) =>
                                                                                                                                                                                                                                                                                                                                        prev.map((tx) =>
                                                                                                                                                                                                                                                                                                                                                  tx.hash === data.hash
                                                                                                                                                                                                                                                                                                                                                              ? { ...tx, status: "confirmed" }
                                                                                                                                                                                                                                                                                                                                                                          : tx
                                                                                                                                                                                                                                                                                                                                                                                  )
                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                            });

                                                                                                                                                                                                                                                                                                                                                                                                return () => {
                                                                                                                                                                                                                                                                                                                                                                                                      socket.off("connect");
                                                                                                                                                                                                                                                                                                                                                                                                            socket.off("newTx");
                                                                                                                                                                                                                                                                                                                                                                                                                  socket.off("txConfirmed");
                                                                                                                                                                                                                                                                                                                                                                                                                      };
                                                                                                                                                                                                                                                                                                                                                                                                                        }, []);

                                                                                                                                                                                                                                                                                                                                                                                                                          /* ================= UI ================= */
                                                                                                                                                                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="min-h-screen bg-black text-white p-4 pb-28">

                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* BALANCE CARD */}
                                                                                                                                                                                                                                                                                                                                                                                                                                            <BalanceCard
                                                                                                                                                                                                                                                                                                                                                                                                                                                    balance={formatBalance(balance)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                            token={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onReceive={() => setShowReceive(true)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onScanner={() => alert("Scanner coming soon")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onVirtualCard={() => setShowCard(true)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* TOKEN SELECTOR */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="mt-5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <TokenSelector
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onChange={setTokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* SEND FORM */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <SendForm
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            recipient={recipient}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setRecipient={setRecipient}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            amount={amount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setAmount={setAmount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            tokenSymbol={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    balance={formatBalance(balance)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onSend={sendTx}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* TRANSACTIONS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <TransactionHistory
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              liveTxs={liveTxs}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* MODALS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <ReceiveModal
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        isOpen={showReceive}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onClose={() => setShowReceive(false)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <VirtualCard
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            isOpen={showCard}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onClose={() => setShowCard(false)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            balance={formatBalance(balance)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    token={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* BOTTOM NAV */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <BottomNav
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      active="pay"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onChange={(tab) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        alert(`Navigate to ${tab} (add router later)`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {/* TX HASH DEBUG */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {txHash && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="mt-4 text-xs text-green-400 break-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Last Tx: {txHash}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }